+
+        let di_all = build_di(&intervals);
+
+        let mut di_split = DisjointIntervals::new();
+        for &(s, e) in &intervals[..split] {
+            di_split.insert(s, e);
+        }
+        for &(s, e) in &intervals[split..] {
